CREATE OR REPLACE FUNCTION public.audit_asset_changes()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_before_data jsonb;
  v_after_data jsonb;
  v_action_type audit_action_type;
  v_audit_id bigint;
  v_user_name text;
  v_building_number bigint;
BEGIN
  -- Get building number (from OLD for DELETE/UPDATE, from NEW for INSERT)
  v_building_number := COALESCE(OLD.building_number, NEW.building_number);

  -- Determine action type based on operation
  -- Always create ONE audit record with both asset and building data in the same JSON
  IF TG_OP = 'INSERT' THEN
    v_action_type := 'manual_update';
    -- Before: building state (no asset yet) - consistent structure
    v_before_data := jsonb_build_object(
      'asset', NULL,
      'building', (get_building_audit_data(v_building_number)->'building')
    );
    -- After: both asset and building state - consistent structure
    v_after_data := get_asset_audit_data(NEW.asset_id);
  ELSIF TG_OP = 'UPDATE' THEN
    v_action_type := 'manual_update';
    -- Before: both asset and building state before update - consistent structure
    -- Note: Since this is AFTER trigger, building might have been updated by other triggers
    -- but we capture the current state which should reflect pre-update building state
    v_before_data := jsonb_build_object(
      'asset', to_jsonb(OLD.*),
      'building', (get_building_audit_data(v_building_number)->'building')
    );
    -- After: both asset and building state after update - consistent structure
    v_after_data := get_asset_audit_data(NEW.asset_id);
  ELSIF TG_OP = 'DELETE' THEN
    v_action_type := 'manual_update';
    -- Before: both asset and building state before deletion - consistent structure
    v_before_data := get_asset_audit_data(OLD.asset_id);
    -- After: building state (no asset anymore) - consistent structure
    v_after_data := jsonb_build_object(
      'asset', NULL,
      'building', (get_building_audit_data(v_building_number)->'building')
    );
  END IF;

  -- Get current user from session or use default
  BEGIN
    -- Try to get user from Supabase auth context
    v_user_name := coalesce(
      current_setting('request.jwt.claims', true)::json->>'email',
      current_setting('request.jwt.claims', true)::json->>'sub',
      'default'
    );
  EXCEPTION WHEN OTHERS THEN
    v_user_name := 'default';
  END;

  -- Log the audit entry and get the audit_id
  SELECT log_audit_entry(
    v_action_type,
    'asset',
    COALESCE(NEW.asset_id::text, OLD.asset_id::text),
    v_user_name,
    v_before_data,
    v_after_data,
    'Automatic audit log: ' || TG_OP || ' operation on asset'
  ) INTO v_audit_id;

  -- Update the asset's action_id
  IF TG_OP != 'DELETE' THEN
    NEW.action_id := v_audit_id;
  END IF;

  -- Store audit_id in session variable for history trigger to use
  PERFORM set_config('app.current_audit_id', v_audit_id::text, false);

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.audit_building_changes()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_before_data jsonb;
  v_after_data jsonb;
  v_action_type audit_action_type;
  v_audit_id bigint;
  v_user_name text;
BEGIN
  -- Determine action type based on operation
  IF TG_OP = 'INSERT' THEN
    v_action_type := 'manual_update';
    v_before_data := NULL;
    v_after_data := get_building_audit_data(NEW.building_number);
  ELSIF TG_OP = 'UPDATE' THEN
    v_action_type := 'manual_update';
    v_before_data := get_building_audit_data(OLD.building_number);
    v_after_data := get_building_audit_data(NEW.building_number);
  ELSIF TG_OP = 'DELETE' THEN
    v_action_type := 'manual_update';
    v_before_data := get_building_audit_data(OLD.building_number);
    v_after_data := NULL;
  END IF;

  -- Get current user from session or use default
  BEGIN
    -- Try to get user from Supabase auth context
    v_user_name := coalesce(
      current_setting('request.jwt.claims', true)::json->>'email',
      current_setting('request.jwt.claims', true)::json->>'sub',
      'default'
    );
  EXCEPTION WHEN OTHERS THEN
    v_user_name := 'default';
  END;

  -- Log the audit entry and update the building's action_id
  SELECT log_audit_entry(
    v_action_type,
    'building',
    COALESCE(NEW.building_number::text, OLD.building_number::text),
    v_user_name,
    v_before_data,
    v_after_data,
    'Automatic audit log: ' || TG_OP || ' operation on building'
  ) INTO v_audit_id;

  -- Update the building's action_id
  IF TG_OP != 'DELETE' THEN
    NEW.action_id := v_audit_id;
  END IF;

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$function$

CREATE OR REPLACE FUNCTION public.auto_set_distribution_flags_on_change()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_business_residence TEXT;
  v_type_changed BOOLEAN := FALSE;
  v_size_changed BOOLEAN := FALSE;
  v_old_type TEXT;
  v_new_type TEXT;
BEGIN
  -- Only process INSERT or UPDATE
  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  END IF;

  -- Skip if no building_number
  IF NEW.building_number IS NULL THEN
    RETURN NEW;
  END IF;

  -- Check if main_asset_type changed
  IF TG_OP = 'UPDATE' THEN
    v_old_type := OLD.main_asset_type;
    v_new_type := NEW.main_asset_type;

    IF (OLD.main_asset_type IS DISTINCT FROM NEW.main_asset_type) THEN
      v_type_changed := TRUE;
    END IF;

    -- Check if asset_size changed (but we'll skip flag setting for size changes)
    IF (OLD.asset_size IS DISTINCT FROM NEW.asset_size) THEN
      v_size_changed := TRUE;
    END IF;
  ELSE
    -- For INSERT, check if asset_size is set
    IF NEW.asset_size IS NOT NULL AND NEW.asset_size > 0 THEN
      v_size_changed := TRUE;
    END IF;
    v_type_changed := TRUE; -- New asset always checks type
  END IF;

  -- Only proceed if type changed (skip size changes - handled in save_assets_bulk_transactional)
  IF NOT v_type_changed THEN
    RETURN NEW;
  END IF;

  -- Get business_residence for the asset type
  SELECT business_residence INTO v_business_residence
  FROM asset_types
  WHERE name = NEW.main_asset_type;

  -- Set appropriate distribution flag based on business_residence
  -- NOTE: We only set flags for type changes here, NOT for size changes
  -- Size changes are handled in save_assets_bulk_transactional with proper tab context
  IF v_business_residence = 'עסקים' THEN
    -- Business asset type changed → set business distribution flag only
    -- BUT only if building has business_shared_area > 0
    UPDATE buildings
    SET need_business_distribution = true
    WHERE building_number = NEW.building_number
      AND COALESCE(business_shared_area, 0) > 0;
  ELSIF v_business_residence = 'מגורים' THEN
    -- Residence asset type changed → set residence distribution flag only
    UPDATE buildings
    SET need_residence_distribution = true
    WHERE building_number = NEW.building_number;
  END IF;

  RETURN NEW;
END;
$function$

CREATE OR REPLACE FUNCTION public.auto_update_building_total_area()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_building_number BIGINT;
BEGIN
  -- Determine building_number based on operation
  IF TG_OP = 'DELETE' THEN
    v_building_number := OLD.building_number;
  ELSE
    v_building_number := NEW.building_number;
  END IF;

  -- Skip if no building_number
  IF v_building_number IS NULL THEN
    IF TG_OP = 'DELETE' THEN
      RETURN OLD;
    ELSE
      RETURN NEW;
    END IF;
  END IF;

  -- Update building total area
  -- This is idempotent - safe to call multiple times
  PERFORM update_building_total_area(v_building_number);

  IF TG_OP = 'DELETE' THEN
    RETURN OLD;
  ELSE
    RETURN NEW;
  END IF;
END;
$function$

